 14→fn wait_for_port(shared: *TcpShared) u16 {
 15→    while (!shared.ready.load(.acquire)) {
 16→        const req = std.os.linux.timespec{
 17→            .sec = 0,
 18→            .nsec = std.time.ns_per_ms,
 19→        };
 20→        _ = std.os.linux.nanosleep(&req, null);
 21→    }
 22→    const port = shared.port.load(.acquire);
 23→    std.debug.assert(port != 0);
 24→    return port;
 25→}
