2474→fn batchDrainReady(batch: *Io.Batch) Io.Timeout.Error!void {
2475→    while (@atomicRmw(?*anyopaque, &batch.userdata, .Xchg, null, .acquire)) |head| {
2476→        var next: usize = @intFromPtr(head);
2477→        var timeout = false;
2478→        while (cond: switch (@as(u2, @truncate(next))) {
2479→            0b00 => if (timeout) return error.Timeout else false,
2480→            0b01 => {
2481→                assert(!timeout);
2482→                return error.Timeout;
2483→            },
2484→            0b10 => true,
2485→            0b11 => {
2486→                assert(!timeout);
2487→                timeout = true;
2488→                break :cond true;
2489→            },
2490→        }) {
2491→            var operation_userdata: *Io.Operation.Storage.Pending.Userdata =
2492→                @ptrFromInt(next & ~@as(usize, 0b11));
2493→            next = operation_userdata[0];
2494→            const completion: Completion = .{
2495→                .result = @bitCast(@as(u32, @intCast(operation_userdata[1]))),
2496→                .flags = @intCast(operation_userdata[2]),
2497→            };
2498→            const pending: *Io.Operation.Storage.Pending =
2499→                @fieldParentPtr("userdata", operation_userdata);
2500→            const storage: *Io.Operation.Storage = @fieldParentPtr("pending", pending);
2501→            const index: Io.Operation.OptionalIndex = .fromIndex(storage - batch.storage.ptr);
2502→            assert(completion.flags & linux.IORING_CQE_F_SKIP == 0);
2503→            switch (pending.node.prev) {
2504→                .none => batch.pending.head = pending.node.next,
2505→                else => |prev_index| batch.storage[prev_index.toIndex()].pending.node.next =
2506→                    pending.node.next,
2507→            }
2508→            switch (pending.node.next) {
2509→                .none => batch.pending.tail = pending.node.prev,
2510→                else => |prev_index| batch.storage[prev_index.toIndex()].pending.node.prev =
2511→                    pending.node.prev,
2512→            }
2513→            if (@as(?Io.Operation.Result, result: switch (pending.tag) {
2514→                .file_read_streaming => .{
2515→                    .file_read_streaming = switch (completion.errno()) {
2516→                        .SUCCESS => @as(u32, @bitCast(completion.result)),
2517→                        .INTR => 0,
2518→                        .CANCELED => break :result null,
2519→                        .INVAL => |err| errnoBug(err),

2540→                        .BADF => error.NotOpenForWriting, // Can be a race condition.
2541→                        .DESTADDRREQ => |err| errnoBug(err), // `connect` was never called.
2542→                        .DQUOT => error.DiskQuota,
2543→                        .FBIG => error.FileTooBig,
2544→                        .IO => error.InputOutput,
2545→                        .NOSPC => error.NoSpaceLeft,
2546→                        .PERM => error.PermissionDenied,
2547→                        .PIPE => error.BrokenPipe,
2548→                        .CONNRESET => |err| errnoBug(err), // Not a socket handle.
2549→                        .BUSY => error.DeviceBusy,
2550→                        else => |err| unexpectedErrno(err),
2551→                    },
2552→                },
2553→                .device_io_control => unreachable,
2554→                .net_receive => net_receive_result: {
2555→                    const pending_state: *BatchNetReceivePending =
2556→                        @alignCast(@as(*align(1) BatchNetReceivePending, @ptrFromInt(pending.userdata[3])));
2557→                    defer std.heap.page_allocator.destroy(pending_state);
2558→                    break :net_receive_result .{
2559→                        .net_receive = switch (completion.errno()) {
2560→                            .SUCCESS => receive_result: {
2561→                                const data = pending_state.iov.base[0..@intCast(completion.result)];
2562→                                pending_state.message.* = .{
2563→                                    .from = addressFromPosix(&pending_state.storage),
2564→                                    .data = data,
2565→                                    .control = if (pending_state.msg.control) |ptr|
2566→                                        @as([*]u8, @ptrCast(ptr))[0..pending_state.msg.controllen]
2567→                                    else
2568→                                        pending_state.message.control,
2569→                                    .flags = .{
2570→                                        .eor = pending_state.msg.flags & linux.MSG.EOR != 0,
2571→                                        .trunc = pending_state.msg.flags & linux.MSG.TRUNC != 0,
2572→                                        .ctrunc = pending_state.msg.flags & linux.MSG.CTRUNC != 0,
2573→                                        .oob = pending_state.msg.flags & linux.MSG.OOB != 0,
2574→                                        .errqueue = pending_state.msg.flags & linux.MSG.ERRQUEUE != 0,
2575→                                    },
2576→                                };
2577→                                break :receive_result .{ null, 1 };
2578→                            },
2579→                            .INTR => .{ null, 0 },
2580→                            .CANCELED => break :net_receive_result null,
2581→                            .BADF => .{ errnoBug(.BADF), 0 },
2582→                            .NFILE => .{ error.SystemFdQuotaExceeded, 0 },
2583→                            .MFILE => .{ error.ProcessFdQuotaExceeded, 0 },
2584→                            .FAULT => .{ errnoBug(.FAULT), 0 },
2585→                            .INVAL => .{ errnoBug(.INVAL), 0 },
2586→                            .NOBUFS => .{ error.SystemResources, 0 },
2587→                            .NOMEM => .{ error.SystemResources, 0 },
2588→                            .NOTCONN => .{ error.SocketUnconnected, 0 },
2589→                            .NOTSOCK => .{ errnoBug(.NOTSOCK), 0 },
2590→                            .MSGSIZE => .{ error.MessageOversize, 0 },
2591→                            .PIPE => .{ error.SocketUnconnected, 0 },
2592→                            .OPNOTSUPP => .{ errnoBug(.OPNOTSUPP), 0 },
2593→                            .CONNRESET => .{ error.ConnectionResetByPeer, 0 },
2594→                            .NETDOWN => .{ error.NetworkDown, 0 },
2595→                            else => |err| .{ unexpectedErrno(err), 0 },
2596→                        },
2597→                    };
2598→                },
2599→            })) |result| {
2600→                switch (batch.completed.tail) {
2601→                    .none => batch.completed.head = index,
2602→                    else => |tail_index| batch.storage[tail_index.toIndex()].completion.node.next =
2603→                        index,
2604→                }
2605→                storage.* = .{ .completion = .{ .node = .{ .next = .none }, .result = result } };
2606→                batch.completed.tail = index;
2607→            } else {
2608→                switch (batch.unused.tail) {
2609→                    .none => batch.unused.head = index,
2610→                    else => |tail_index| batch.storage[tail_index.toIndex()].unused.next = index,
2611→                }
2612→                storage.* = .{ .unused = .{ .prev = batch.unused.tail, .next = .none } };
2613→                batch.unused.tail = index;
2614→            }
2615→        }
2616→    }
2617→}
