13550→fn addWsaBuf(v: []ws2_32.WSABUF, i: *u32, bytes: []const u8) void {
13551→    const cap = std.math.maxInt(u32);
13552→    var remaining = bytes;
13553→    while (remaining.len > cap) {
13554→        if (v.len - i.* == 0) return;
13555→        v[i.*] = .{ .buf = @constCast(remaining.ptr), .len = cap };
13556→        i.* += 1;
13557→        remaining = remaining[cap..];
13558→    } else {
13559→        @branchHint(.likely);
13560→        if (v.len - i.* == 0) return;
13561→        v[i.*] = .{ .buf = @constCast(remaining.ptr), .len = @intCast(remaining.len) };
13562→        i.* += 1;
13563→    }
13564→}
