fn operationName(
    ev: *Evented,
    cancel_region: *CancelRegion,  // or sync: *CancelRegion.Sync for sync operations
    fd: fd_t,
    // ... operation-specific parameters
) ReturnError!ReturnType {
    while (true) {
        const thread = try cancel_region.awaitIoUring();
        thread.enqueue().* = .{
            .opcode = .OPNAME,
            .flags = 0,
            .ioprio = 0,
            .fd = fd,
            .off = 0,
            .addr = 0,
            .len = 0,
            .rw_flags = 0,
            .user_data = @intFromPtr(cancel_region.fiber),
            .buf_index = 0,
            .personality = 0,
            .splice_fd_in = 0,
            .addr3 = 0,
            .resv = 0,
        };
        ev.yield(null, .nothing);
        const completion = cancel_region.completion();
        switch (completion.errno()) {
            .SUCCESS => return result,
            .INTR, .CANCELED => {},
            // ... error cases
        }
    }
}
