        .rw_flags = linux.MSG.NOSIGNAL | ...,
        .user_data = @intFromPtr(&storage.pending.userdata) | 0b10,
        .buf_index = 0,
        .personality = 0,
        .splice_fd_in = 0,
        .addr3 = 0,
        .resv = 0,
    };
    break :result null;  // Not yet complete, submitted async
