```zig
fn netRead(
    userdata: ?*anyopaque,
    fd: net.Socket.Handle,
    data: [][]u8,
) net.Stream.Reader.Error!usize {
    const ev: *Evented = @ptrCast(@alignCast(userdata));

    var iovecs_buffer: [max_iovecs_len]iovec = undefined;
    var i: usize = 0;
    for (data) |buf| {
        if (i >= iovecs_buffer.len) break;
        if (buf.len == 0) continue;
        iovecs_buffer[i] = .{ .base = buf.ptr, .len = buf.len };
        i += 1;
    }
    if (i == 0) return 0;

    var cancel_region: CancelRegion = .init();
    defer cancel_region.deinit();
    return ev.preadv(&cancel_region, fd, iovecs_buffer[0..i], null) catch |err| switch (err) {
        error.Canceled => return error.Canceled,
        error.AccessDenied => return error.AccessDenied,
        error.ConnectionResetByPeer => return error.ConnectionResetByPeer,
        error.SocketUnconnected => return error.SocketUnconnected,
        error.SystemResources => return error.SystemResources,
        error.WouldBlock => return errnoBug(.AGAIN),
        error.InputOutput => return unexpectedErrno(.IO),
        error.IsDir => return errnoBug(.ISDIR),
        error.NotOpenForReading => return errnoBug(.BADF),
        error.LockViolation => return errnoBug(.AGAIN),
        error.Unexpected => return error.Unexpected,
    };
}
```

