### 6. THE addBuf() AND IOVEC PATTERN

#### addBuf Implementation - Lines 3760-3769
```zig
/// This is either usize or u32. Since either is fine, let's use the same
/// `addBuf` function for both writing to a file and sending network messages.
const iovlen_t = @FieldType(linux.msghdr_const, "iovlen");

fn addBuf(v: []iovec_const, i: *iovlen_t, bytes: []const u8) void {
    // OS checks ptr addr before length so zero length vectors must be omitted.
    if (bytes.len == 0) return;         // Skip zero-length buffers
    if (v.len - i.* == 0) return;       // Skip if iovec array is full
    v[i.*] = .{ .base = bytes.ptr, .len = bytes.len };
    i.* += 1;
}
```

**Design decisions:**
- Skips empty buffers (OS checks address first, so empty entries waste space)
- Skips if iovec array is full (silently drops data rather than failing)
- Works with both file and network operations (polymorphic over iovlen_t)

#### Usage in netWrite() - Lines 5516-5543
```zig
var iovecs: [max_iovecs_len]iovec_const = undefined;
var msg: linux.msghdr_const = .{
    .name = null,
    .namelen = 0,
    .iov = &iovecs,
    .iovlen = 0,                        // Start with 0 iovecs
    .control = null,
    .controllen = 0,
    .flags = 0,
};
addBuf(&iovecs, &msg.iovlen, header);  // Add header
for (data[0 .. data.len - 1]) |bytes| {
    addBuf(&iovecs, &msg.iovlen, bytes); // Add data chunks
}
const pattern = data[data.len - 1];

// Handle splat (repeated) buffer
var splat_backup_buffer: [splat_buffer_size]u8 = undefined;
if (iovecs.len - msg.iovlen != 0) switch (splat) {
    0 => {},
    1 => addBuf(&iovecs, &msg.iovlen, pattern),
    else => switch (pattern.len) {
        0 => {},
        1 => {
            const splat_buffer = &splat_backup_buffer;
            const memset_len = @min(splat_buffer.len, splat);
            const buf = splat_buffer[0..memset_len];
            @memset(buf, pattern[0]);
            addBuf(&iovecs, &msg.iovlen, buf);
            var remaining_splat = splat - buf.len;
            while (remaining_splat > splat_buffer.len and iovecs.len - msg.iovlen != 0) {
                addBuf(&iovecs, &msg.iovlen, splat_buffer);
                remaining_splat -= splat_buffer.len;
            }
            addBuf(&iovecs, &msg.iovlen, splat_buffer[0..@min(remaining_splat, splat_buffer.len)]);
        },
        else => for (0..@min(splat, iovecs.len - msg.iovlen)) |_| {
            addBuf(&iovecs, &msg.iovlen, pattern);
        },
    },
};

var cancel_region: CancelRegion = .init();
defer cancel_region.deinit();
return ev.netWriteMsg(&cancel_region, handle, &msg, linux.MSG.NOSIGNAL) catch |err| switch (err) {
    // error handling
};
```

