### 4. HOW BATCH OPERATIONS WORK

#### batchDrainSubmitted - Lines 2317-2472

This function processes operations from the batch's `submitted` list and either:
- Immediately completes them (if result available synchronously)
- Submits them to io_uring for async processing

**Structure:**
```zig
fn batchDrainSubmitted(
    ev: *Evented,
    maybe_sync: *CancelRegion.Sync.Maybe,
    batch: *Io.Batch,
    concurrency: bool,
) (Io.ConcurrentError || Io.Cancelable)!void {
    var index = batch.submitted.head;
    if (index == .none) return;
    const thread = try maybe_sync.cancelRegion().awaitIoUring();
    errdefer batch.submitted.head = index;

    while (index != .none) {
        const storage = &batch.storage[index.toIndex()];
        const next_index = storage.submission.node.next;

        // For each operation type, try to submit or complete
        if (@as(?Io.Operation.Result, result: switch (storage.submission.operation) {
            .file_read_streaming => { ... },
            .file_write_streaming => { ... },
            .net_receive => { ... },
            // etc.
        })) |result| {
            // Operation completed synchronously
            switch (batch.completed.tail) {
                .none => batch.completed.head = index,
                else => |tail_index| batch.storage[tail_index.toIndex()].completion.node.next = index,
            }
            batch.completed.tail = index;
            storage.* = .{ .completion = .{ .node = .{ .next = .none }, .result = result } };
        } else {
            // Operation submitted asynchronously
            switch (batch.pending.tail) {
                .none => batch.pending.head = index,
                else => |tail_index| batch.storage[tail_index.toIndex()].pending.node.next = index,
            }
            batch.pending.tail = index;
            storage.pending.userdata[0] = @intFromPtr(batch);  // Link back to batch
        }
        index = next_index;
    }
    batch.submitted = .{ .head = .none, .tail = .none };
}
```

**Key points:**
- Iterates through submitted operations
- For each, tries to set up an SQE with `thread.enqueue()`
- If operation can't be submitted (e.g., needs more space), returns null from switch
- Null result means move to pending; non-null means move to completed
- Pending state allocates storage for operation context (e.g., BatchNetReceivePending)
- userdata[0] stores pointer to batch for completion handler

**Pending state allocation example (net_receive at line 2396-2451):**
```zig
.net_receive => |o| {
    if (o.message_buffer.len == 0 or o.data_buffer.len == 0) {
        break :result .{ .net_receive = .{ null, 0 } };
    }
    const pending_state = std.heap.page_allocator.create(BatchNetReceivePending) catch
        return error.ConcurrencyUnavailable;
    errdefer std.heap.page_allocator.destroy(pending_state);
    pending_state.* = .{
        .message = &o.message_buffer[0],
        .storage = undefined,
        .iov = .{
            .base = o.data_buffer.ptr,
            .len = o.data_buffer.len,
        },
        .msg = .{
            .name = undefined,
            .namelen = @sizeOf(PosixAddress),
            .iov = undefined,
            .iovlen = 1,
            .control = undefined,
            .controllen = o.message_buffer[0].control.len,
            .flags = undefined,
        },
    };
    pending_state.msg.name = &pending_state.storage.any;
    pending_state.msg.iov = (&pending_state.iov)[0..1];
    pending_state.msg.control = if (o.message_buffer[0].control.len == 0)
        null
    else
        o.message_buffer[0].control.ptr;

    storage.* = .{ .pending = .{
        .node = .{ .prev = batch.pending.tail, .next = .none },
        .tag = .net_receive,
        .userdata = undefined,
    } };
    storage.pending.userdata[3] = @intFromPtr(pending_state);

    thread.enqueue().* = .{
        .opcode = .RECVMSG,
        .flags = 0,
        .ioprio = 0,
        .fd = o.socket_handle,
