#### batchDrainReady - Lines 2474-2617

Processes all completions from the batch's completion ring:

```zig
fn batchDrainReady(batch: *Io.Batch) Io.Timeout.Error!void {
    while (@atomicRmw(?*anyopaque, &batch.userdata, .Xchg, null, .acquire)) |head| {
        var next: usize = @intFromPtr(head);
        var timeout = false;

        while (cond: switch (@as(u2, @truncate(next))) {
            0b00 => if (timeout) return error.Timeout else false,
            0b01 => {
                assert(!timeout);
                return error.Timeout;
            },
            0b10 => true,                          // Batch pending data
            0b11 => {
                assert(!timeout);
                timeout = true;
                break :cond true;
            },
        }) {
            // Extract pending operation and its completion
            var operation_userdata: *Io.Operation.Storage.Pending.Userdata =
                @ptrFromInt(next & ~@as(usize, 0b11));
            next = operation_userdata[0];           // Next in chain
            const completion: Completion = .{
                .result = @bitCast(@as(u32, @intCast(operation_userdata[1]))),
                .flags = @intCast(operation_userdata[2]),
            };
            const pending: *Io.Operation.Storage.Pending =
                @fieldParentPtr("userdata", operation_userdata);
            const storage: *Io.Operation.Storage = @fieldParentPtr("pending", pending);
            const index: Io.Operation.OptionalIndex = .fromIndex(storage - batch.storage.ptr);

            // Remove from pending list
            switch (pending.node.prev) {
                .none => batch.pending.head = pending.node.next,
                else => |prev_index| batch.storage[prev_index.toIndex()].pending.node.next =
                    pending.node.next,
            }
            switch (pending.node.next) {
                .none => batch.pending.tail = pending.node.prev,
                else => |next_index| batch.storage[next_index.toIndex()].pending.node.prev =
                    pending.node.prev,
            }

            // Process completion and move to completed or unused list
            if (@as(?Io.Operation.Result, result: switch (pending.tag) {
                .file_read_streaming => .{
                    .file_read_streaming = switch (completion.errno()) {
                        .SUCCESS => @as(u32, @bitCast(completion.result)),
                        .INTR => 0,
                        .CANCELED => break :result null,
                        // ... error cases
                    },
                },
                .file_write_streaming => { ... },
                .net_receive => net_receive_result: {
                    const pending_state: *BatchNetReceivePending =
                        @alignCast(@as(*align(1) BatchNetReceivePending, @ptrFromInt(pending.userdata[3])));
                    defer std.heap.page_allocator.destroy(pending_state);
                    break :net_receive_result .{
                        .net_receive = switch (completion.errno()) {
                            .SUCCESS => receive_result: {
                                const data = pending_state.iov.base[0..@intCast(completion.result)];
                                pending_state.message.* = .{
                                    .from = addressFromPosix(&pending_state.storage),
                                    .data = data,
                                    .control = ...,
                                    .flags = ...,
                                };
                                break :receive_result .{ null, 1 };
                            },
                            .INTR => .{ null, 0 },
                            .CANCELED => break :net_receive_result null,
                            // ... error cases
                        },
                    };
                },
            })) |result| {
                // Completed successfully
                switch (batch.completed.tail) {
                    .none => batch.completed.head = index,
                    else => |tail_index| batch.storage[tail_index.toIndex()].completion.node.next = index,
                }
                storage.* = .{ .completion = .{ .node = .{ .next = .none }, .result = result } };
                batch.completed.tail = index;
            } else {
                // Still pending (CANCELED)
                switch (batch.unused.tail) {
                    .none => batch.unused.head = index,
                    else => |tail_index| batch.storage[tail_index.toIndex()].unused.next = index,
                }
                storage.* = .{ .unused = .{ .prev = batch.unused.tail, .next = .none } };
                batch.unused.tail = index;
            }
        }
    }
}
```

**Key mechanics:**
- Atomically exchanges `batch.userdata` to get completion chain
- Bits 0-1 of pointers encode completion status:
  - 0b00 = normal completion
  - 0b01 = timeout
  - 0b10 = batch pending userdata pointer
  - 0b11 = timeout with remaining work
- userdata[0] = next pointer in chain
- userdata[1-2] = result and flags from CQE
- For batch operations, pending state is heap-allocated and freed after processing
- Results moved to either completed or unused list

