5224→fn netSend(
5225→    userdata: ?*anyopaque,
5226→    handle: net.Socket.Handle,
5227→    messages: []net.OutgoingMessage,
5228→    flags: net.SendFlags,
5229→) struct { ?net.Socket.SendError, usize } {
5230→    const ev: *Evented = @ptrCast(@alignCast(userdata));
5231→    const msg_flags: u32 =
5232→        @as(u32, if (@hasDecl(linux.MSG, "CONFIRM") and flags.confirm) linux.MSG.CONFIRM else 0) |
5233→        @as(u32, if (@hasDecl(linux.MSG, "DONTROUTE") and flags.dont_route) linux.MSG.DONTROUTE else 0) |
5234→        @as(u32, if (@hasDecl(linux.MSG, "EOR") and flags.eor) linux.MSG.EOR else 0) |
5235→        @as(u32, if (@hasDecl(linux.MSG, "OOB") and flags.oob) linux.MSG.OOB else 0) |
5236→        @as(u32, if (@hasDecl(linux.MSG, "FASTOPEN") and flags.fastopen) linux.MSG.FASTOPEN else 0) |
5237→        linux.MSG.NOSIGNAL;
5238→
5239→    var cancel_region: CancelRegion = .init();
5240→    defer cancel_region.deinit();
5241→    var i: usize = 0;
5242→    while (i < messages.len) : (i += 1) {
5243→        netSendOne(ev, &cancel_region, handle, &messages[i], msg_flags) catch |err| return .{ err, i };
5244→    }
