5248→fn netSendOne(
5249→    ev: *Evented,
5250→    cancel_region: *CancelRegion,
5251→    handle: net.Socket.Handle,
5252→    message: *net.OutgoingMessage,
5253→    flags: u32,
5254→) net.Socket.SendError!void {
5255→    var addr: PosixAddress = undefined;
5256→    var iov: iovec_const = .{ .base = message.data_ptr, .len = message.data_len };
5257→    const msg: linux.msghdr_const = .{
5258→        .name = &addr.any,
5259→        .namelen = addressToPosix(message.address, &addr),
5260→        .iov = (&iov)[0..1],
5261→        .iovlen = 1,
5262→        .control = if (message.control.len == 0) null else message.control.ptr,
5263→        .controllen = message.control.len,
5264→        .flags = 0,
5265→    };
5266→
5267→    while (true) {
5268→        const thread = try cancel_region.awaitIoUring();
5269→        thread.enqueue().* = .{
5270→            .opcode = .SENDMSG,
5271→            .flags = 0,
5272→            .ioprio = 0,
5273→            .fd = handle,
5274→            .off = 0,
5275→            .addr = @intFromPtr(&msg),
5276→            .len = 1,
5277→            .rw_flags = flags,
5278→            .user_data = @intFromPtr(cancel_region.fiber),
5279→            .buf_index = 0,
5280→            .personality = 0,
5281→            .splice_fd_in = 0,
5282→            .addr3 = 0,
5283→            .resv = 0,
5284→        };
5285→        ev.yield(null, .nothing);
5286→        const completion = cancel_region.completion();
5287→        switch (completion.errno()) {
5288→            .SUCCESS => {
5289→                message.data_len = @intCast(completion.result);
5290→                return;
5291→            },
5292→            .INTR, .CANCELED => {},
5293→            .ACCES => return error.AccessDenied,
5294→            .ALREADY => return error.FastOpenAlreadyInProgress,
5295→            .BADF => |err| return errnoBug(err),
5296→            .CONNRESET => return error.ConnectionResetByPeer,
5297→            .DESTADDRREQ => |err| return errnoBug(err),
5298→            .FAULT => |err| return errnoBug(err),
5299→            .INVAL => |err| return errnoBug(err),
5300→            .ISCONN => |err| return errnoBug(err),
5301→            .MSGSIZE => return error.MessageOversize,
5302→            .NOBUFS => return error.SystemResources,
5303→            .NOMEM => return error.SystemResources,
5304→            .NOTSOCK => |err| return errnoBug(err),
5305→            .OPNOTSUPP => |err| return errnoBug(err),
5306→            .PIPE => return error.SocketUnconnected,
5307→            .AFNOSUPPORT => return error.AddressFamilyUnsupported,
5308→            .HOSTUNREACH => return error.HostUnreachable,
5309→            .NETUNREACH => return error.NetworkUnreachable,
5310→            .NOTCONN => return error.SocketUnconnected,
5311→            .NETDOWN => return error.NetworkDown,
5312→            .CONNREFUSED => return error.ConnectionRefused,
5313→            else => |err| return unexpectedErrno(err),
5314→        }
5315→    }
5316→}
