5497→fn netWrite(
5498→    userdata: ?*anyopaque,
5499→    handle: net.Socket.Handle,
5500→    header: []const u8,
5501→    data: []const []const u8,
5502→    splat: usize,
5503→) net.Stream.Writer.Error!usize {
5504→    const ev: *Evented = @ptrCast(@alignCast(userdata));
5505→
5506→    var iovecs: [max_iovecs_len]iovec_const = undefined;
5507→    var msg: linux.msghdr_const = .{
5508→        .name = null,
5509→        .namelen = 0,
5510→        .iov = &iovecs,
5511→        .iovlen = 0,
5512→        .control = null,
5513→        .controllen = 0,
5514→        .flags = 0,
5515→    };
5516→    addBuf(&iovecs, &msg.iovlen, header);
5517→    for (data[0 .. data.len - 1]) |bytes| addBuf(&iovecs, &msg.iovlen, bytes);
5518→    const pattern = data[data.len - 1];
5519→
5520→    var splat_backup_buffer: [splat_buffer_size]u8 = undefined;
5521→    if (iovecs.len - msg.iovlen != 0) switch (splat) {
5522→        0 => {},
5523→        1 => addBuf(&iovecs, &msg.iovlen, pattern),
5524→        else => switch (pattern.len) {
5525→            0 => {},
5526→            1 => {
5527→                const splat_buffer = &splat_backup_buffer;
5528→                const memset_len = @min(splat_buffer.len, splat);
5529→                const buf = splat_buffer[0..memset_len];
5530→                @memset(buf, pattern[0]);
5531→                addBuf(&iovecs, &msg.iovlen, buf);
5532→                var remaining_splat = splat - buf.len;
5533→                while (remaining_splat > splat_buffer.len and iovecs.len - msg.iovlen != 0) {
5534→                    addBuf(&iovecs, &msg.iovlen, splat_buffer);
5535→                    remaining_splat -= splat_buffer.len;
5536→                }
5537→                addBuf(&iovecs, &msg.iovlen, splat_buffer[0..@min(remaining_splat, splat_buffer.len)]);
5538→            },
5539→            else => for (0..@min(splat, iovecs.len - msg.iovlen)) |_| {
5540→                addBuf(&iovecs, &msg.iovlen, pattern);
5541→            },
5542→        },
5543→    };
5544→
5545→    var cancel_region: CancelRegion = .init();
5546→    defer cancel_region.deinit();
5547→    return ev.netWriteMsg(&cancel_region, handle, &msg, linux.MSG.NOSIGNAL) catch |err| switch (err) {
5548→        error.Canceled => return error.Canceled,
5549→        error.FastOpenAlreadyInProgress => return error.FastOpenAlreadyInProgress,
5550→        error.ConnectionResetByPeer => return error.ConnectionResetByPeer,
5551→        error.SystemResources => return error.SystemResources,
5552→        error.NetworkUnreachable => return error.NetworkUnreachable,
5553→        error.HostUnreachable => return error.HostUnreachable,
5554→        error.NetworkDown => return error.NetworkDown,
5555→        error.ConnectionRefused => return error.ConnectionRefused,
5556→        error.AddressFamilyUnsupported => return error.AddressFamilyUnsupported,
5557→        error.SocketUnconnected => return error.SocketUnconnected,
5558→        error.SocketNotBound => return error.SocketNotBound,
5559→        else => |e| return e,
5560→    };
5561→}
